import { useState } from 'react'
import { sanitiseProfile } from '../utils/sanitiser.js'
import { askCPF } from '../utils/claudeClient.js'

// Chat with Claude over the SANITISED profile. The API key lives in sessionStorage
// by default (cleared when the tab closes). A transparency toggle reveals the exact
// anonymised payload that was sent — the proof of the zero-retention design.

const SUGGESTIONS = [
  'Can I withdraw from my CPF at 55?',
  'Am I on track to hit the Full Retirement Sum?',
  'How does CPF interest grow my balances?',
  'What happens to my Special Account at 55?',
]

export default function ChatInterface({ profile, apiKey, onApiKeyChange }) {
  const [messages, setMessages] = useState([])
  const [input, setInput] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)
  const [keyDraft, setKeyDraft] = useState(apiKey ?? '')
  const [showPayloadFor, setShowPayloadFor] = useState(null)

  async function send(question) {
    const q = (question ?? input).trim()
    if (!q || loading) return
    if (!apiKey) {
      setError('Enter your Anthropic API key first.')
      return
    }
    setError(null)
    setInput('')
    const history = messages.map((m) => ({ role: m.role, content: m.content }))
    setMessages((m) => [...m, { role: 'user', content: q }])
    setLoading(true)
    try {
      const sanitised = sanitiseProfile(profile)
      const { text, sentPayload } = await askCPF({
        apiKey,
        sanitisedProfile: sanitised,
        rawProfile: profile,
        question: q,
        history,
      })
      setMessages((m) => [...m, { role: 'assistant', content: text, sentPayload }])
    } catch (e) {
      setError(e.message || 'Request failed.')
    } finally {
      setLoading(false)
    }
  }

  return (
    <section className="card chat">
      <h2>Ask about your CPF</h2>

      {!apiKey && (
        <div className="key-entry">
          <p className="muted">
            Bring your own Anthropic API key. It stays in this browser session only.
          </p>
          <div className="key-row">
            <input
              type="password"
              placeholder="sk-ant-..."
              value={keyDraft}
              onChange={(e) => setKeyDraft(e.target.value)}
            />
            <button onClick={() => onApiKeyChange(keyDraft.trim())} disabled={!keyDraft.trim()}>
              Save key
            </button>
          </div>
        </div>
      )}

      <div className="messages">
        {messages.length === 0 && (
          <div className="suggestions">
            {SUGGESTIONS.map((s) => (
              <button key={s} className="chip" onClick={() => send(s)} disabled={loading}>
                {s}
              </button>
            ))}
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`}>
            <div className="bubble">{m.content}</div>
            {m.sentPayload && (
              <div className="transparency">
                <button
                  className="link"
                  onClick={() => setShowPayloadFor(showPayloadFor === i ? null : i)}
                >
                  {showPayloadFor === i ? 'Hide' : 'See exactly what was sent'}
                </button>
                {showPayloadFor === i && (
                  <pre className="payload">{JSON.stringify(m.sentPayload, null, 2)}</pre>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && <div className="msg assistant"><div className="bubble">Thinking…</div></div>}
      </div>

      {error && <p className="error">{error}</p>}

      <div className="composer">
        <input
          type="text"
          placeholder="Ask a CPF question…"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && send()}
          disabled={loading}
        />
        <button onClick={() => send()} disabled={loading || !input.trim()}>
          Send
        </button>
      </div>
      {apiKey && (
        <button className="link clear-key" onClick={() => onApiKeyChange('')}>
          Clear API key
        </button>
      )}
    </section>
  )
}

