:root {
  --bg: #0f172a;
  --card: #1e293b;
  --card-2: #273449;
  --text: #e2e8f0;
  --muted: #94a3b8;
  --accent: #38bdf8;
  --accent-strong: #0ea5e9;
  --border: #334155;
  --error: #f87171;
  --ok: #34d399;
}

* { box-sizing: border-box; }

.app {
  max-width: 1100px;
  margin: 0 auto;
  padding: 1.5rem 1.25rem 3rem;
}

.app-header h1 {
  margin: 0;
  font-size: 1.9rem;
  letter-spacing: -0.02em;
}
.tagline { margin: 0.2rem 0 0.8rem; color: var(--muted); }

.privacy-banner {
  background: linear-gradient(90deg, rgba(14,165,233,0.18), rgba(52,211,153,0.12));
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.6rem 0.9rem;
  font-size: 0.9rem;
}

.layout {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1.25rem;
  margin-top: 1.25rem;
  align-items: start;
}
.col-left, .col-right { display: flex; flex-direction: column; gap: 1.25rem; }

@media (max-width: 860px) {
  .layout { grid-template-columns: 1fr; }
}

.card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 1.1rem 1.15rem;
}
.card h2 { margin: 0 0 0.4rem; font-size: 1.1rem; }
.muted { color: var(--muted); font-size: 0.85rem; margin: 0.2rem 0 0.8rem; }

/* Balance input */
.fields { display: grid; grid-template-columns: 1fr 1fr; gap: 0.7rem; }
.field { display: flex; flex-direction: column; gap: 0.25rem; font-size: 0.82rem; }
.field span { color: var(--muted); }
input[type="text"], input[type="password"] {
  background: var(--card-2);
  border: 1px solid var(--border);
  border-radius: 8px;
  color: var(--text);
  padding: 0.5rem 0.6rem;
  font-size: 0.95rem;
  width: 100%;
}
input:focus { outline: 2px solid var(--accent-strong); outline-offset: 0; }
.error { color: var(--error); font-size: 0.78rem; }
.remember { display: flex; align-items: center; gap: 0.5rem; margin-top: 0.8rem; font-size: 0.82rem; color: var(--muted); }

button {
  background: var(--accent-strong);
  color: #06121f;
  border: none;
  border-radius: 8px;
  padding: 0.5rem 0.9rem;
  font-weight: 600;
  cursor: pointer;
}
button:disabled { opacity: 0.45; cursor: not-allowed; }
button.link {
  background: none; color: var(--accent); padding: 0; font-weight: 500;
  text-decoration: underline; font-size: 0.8rem;
}

/* Projection */
.milestones { display: grid; grid-template-columns: repeat(3, 1fr); gap: 0.6rem; margin-bottom: 0.8rem; }
.milestone {
  background: var(--card-2); border-radius: 10px; padding: 0.6rem; display: flex; flex-direction: column; gap: 0.15rem;
}
.m-label { font-size: 0.72rem; color: var(--muted); }
.m-value { font-size: 1.1rem; font-weight: 700; }
.m-sub { font-size: 0.72rem; color: var(--accent); }
.chart { width: 100%; height: auto; background: var(--card-2); border-radius: 10px; }
.x-label { fill: var(--muted); font-size: 11px; }
.legend { display: flex; gap: 1rem; margin-top: 0.5rem; font-size: 0.8rem; color: var(--muted); }
.legend i { display: inline-block; width: 11px; height: 11px; border-radius: 3px; margin-right: 0.3rem; vertical-align: middle; }

/* Chat */
.key-entry { background: var(--card-2); border-radius: 10px; padding: 0.7rem; margin-bottom: 0.8rem; }
.key-row { display: flex; gap: 0.5rem; }
.messages { display: flex; flex-direction: column; gap: 0.7rem; min-height: 120px; margin-bottom: 0.8rem; }
.suggestions { display: flex; flex-wrap: wrap; gap: 0.45rem; }
.chip {
  background: var(--card-2); color: var(--text); border: 1px solid var(--border);
  font-weight: 500; font-size: 0.8rem; border-radius: 999px; padding: 0.4rem 0.7rem;
}
.msg { display: flex; flex-direction: column; gap: 0.25rem; }
.msg.user { align-items: flex-end; }
.bubble {
  max-width: 90%; padding: 0.6rem 0.8rem; border-radius: 12px; white-space: pre-wrap;
  line-height: 1.45; font-size: 0.9rem;
}
.msg.user .bubble { background: var(--accent-strong); color: #06121f; }
.msg.assistant .bubble { background: var(--card-2); }
.transparency { font-size: 0.78rem; }
.payload {
  background: #0b1220; border: 1px solid var(--border); border-radius: 8px;
  padding: 0.6rem; overflow-x: auto; font-size: 0.72rem; max-height: 260px;
}
.composer { display: flex; gap: 0.5rem; }
.clear-key { margin-top: 0.6rem; }

.app-footer { margin-top: 2rem; text-align: center; }

