// Flatten the KB into a compact, model-friendly context block. Optionally
// filter sections by key so we only send what a given question needs.
export function buildRulesContext(sectionKeys = null) {
  const keys = sectionKeys ?? Object.keys(cpfRules).filter((k) => typeof cpfRules[k] === 'object')
  const lines = [`CPF rules knowledge base (year ${cpfRules.year}, ${cpfRules.currency}):`]
  for (const key of keys) {
    const section = cpfRules[key]
    if (!section || typeof section !== 'object' || !section.statements) continue
    lines.push(`\n## ${key}`)
    for (const s of section.statements) lines.push(`- ${s}`)
    if (section.source) lines.push(`  (source: ${section.source})`)
  }
  return lines.join('\n')
}

// Naive keyword router: pick the rule sections most relevant to a question so
// the context stays small. Always includes retirementSums + withdrawals as a base.
export function selectRelevantSections(question = '') {
  const q = question.toLowerCase()
  const selected = new Set(['retirementSums', 'withdrawals'])
  const add = (...keys) => keys.forEach((k) => selected.add(k))
  if (/interest|grow|return|compound/.test(q)) add('interestRates')
  if (/contribut|salary|wage|income|employer|ceiling/.test(q)) add('contributionRates', 'wageCeilings', 'allocation')
  if (/medisave|ma\b|health|medical|bhs/.test(q)) add('bhs', 'accountStructure')
  if (/account|oa\b|sa\b|special|ordinary|transfer|55/.test(q)) add('accountStructure')
  if (/allocat|split/.test(q)) add('allocation')
  return [...selected]
}

