import { useMemo } from 'react'
import { projectBalances, projectedRAAt55, yearsToFRS } from '../utils/projection.js'
import { cpfRules } from '../data/cpfRules.js'

// Local projection display. Computes everything in-browser — no network calls.
// Renders an inline-SVG stacked chart of OA/SA/MA growth plus milestone cards.

const fmt = (n) => '$' + Math.round(n).toLocaleString('en-US')
const COLORS = { oa: '#2563eb', sa: '#16a34a', ma: '#db2777' }

export default function ProjectionPanel({ profile }) {
  const ready = profile.age !== '' && profile.age != null && Number(profile.age) > 0

  const data = useMemo(() => {
    if (!ready) return null
    const series = projectBalances(profile, 65)
    return {
      series,
      ra: projectedRAAt55(profile),
      frsTiming: yearsToFRS(profile),
      maxTotal: Math.max(...series.map((p) => p.total), 1),
    }
  }, [profile, ready])

  if (!ready) {
    return (
      <section className="card projection">
        <h2>Projection</h2>
        <p className="muted">Enter your age (and balances) to see a local savings projection.</p>
      </section>
    )
  }

  const { series, ra, frsTiming, maxTotal } = data
  const W = 520
  const H = 200
  const pad = { l: 8, r: 8, t: 10, b: 22 }
  const innerW = W - pad.l - pad.r
  const innerH = H - pad.t - pad.b
  const barW = Math.max(2, (innerW / series.length) * 0.7)
  const step = innerW / series.length

  return (
    <section className="card projection">
      <h2>Projection to age 65</h2>
      <p className="muted">
        Estimate using CPF floor interest (OA {cpfRules.interestRates.oa}%, SA/MA{' '}
        {cpfRules.interestRates.sa}%). Computed in your browser — not financial advice.
      </p>

      <div className="milestones">
        <div className="milestone">
          <span className="m-label">Projected RA at 55</span>
          <span className="m-value">{ra ? fmt(ra.ra) : '—'}</span>
          <span className="m-sub">
            {ra?.meetsFRS ? 'Meets FRS ✓' : ra?.meetsBRS ? 'Meets BRS' : 'Below BRS'}
          </span>
        </div>
        <div className="milestone">
          <span className="m-label">Reaches FRS ({fmt(cpfRules.retirementSums.frs.amount)})</span>
          <span className="m-value">
            {frsTiming?.atAge ? `age ${frsTiming.atAge}` : 'not by 55'}
          </span>
          <span className="m-sub">
            {frsTiming?.years != null ? `in ~${frsTiming.years} yrs` : 'under this model'}
          </span>
        </div>
        <div className="milestone">
          <span className="m-label">Total CPF now</span>
          <span className="m-value">{fmt(series[0].total)}</span>
          <span className="m-sub">at age {series[0].age}</span>
        </div>
      </div>

      <svg className="chart" viewBox={`0 0 ${W} ${H}`} role="img" aria-label="Projected CPF balances">
        {series.map((p, i) => {
          const x = pad.l + i * step + (step - barW) / 2
          const hOA = (p.oa / maxTotal) * innerH
          const hSA = (p.sa / maxTotal) * innerH
          const hMA = (p.ma / maxTotal) * innerH
          let y = pad.t + innerH
          const seg = (h, color, key) => {
            y -= h
            return <rect key={key} x={x} y={y} width={barW} height={h} fill={color} />
          }
          const showLabel = i === 0 || i === series.length - 1 || p.age === 55
          return (
            <g key={p.age}>
              {seg(hMA, COLORS.ma, 'ma')}
              {seg(hSA, COLORS.sa, 'sa')}
              {seg(hOA, COLORS.oa, 'oa')}
              {showLabel && (
                <text x={x + barW / 2} y={H - 6} textAnchor="middle" className="x-label">
                  {p.age}
                </text>
              )}
            </g>
          )
        })}
      </svg>

      <div className="legend">
        <span><i style={{ background: COLORS.oa }} /> OA</span>
        <span><i style={{ background: COLORS.sa }} /> SA</span>
        <span><i style={{ background: COLORS.ma }} /> MA</span>
      </div>
    </section>
  )
}

