import { useState } from 'react'

// Controlled form for the user's CPF position. Raw values are lifted to App via
// onChange and otherwise stay in the browser. "Remember on this device" is opt-in
// and uses localStorage; by default nothing is persisted.

const FIELDS = [
  { key: 'oa', label: 'Ordinary Account (OA)', placeholder: 'e.g. 80000' },
  { key: 'sa', label: 'Special Account (SA)', placeholder: 'e.g. 60000' },
  { key: 'ma', label: 'MediSave Account (MA)', placeholder: 'e.g. 40000' },
  { key: 'age', label: 'Age', placeholder: 'e.g. 42', integer: true },
  { key: 'income', label: 'Monthly income (optional)', placeholder: 'e.g. 6000' },
]

export default function BalanceInput({ profile, onChange, remember, onRememberChange }) {
  const [errors, setErrors] = useState({})

  function handleField(key, value) {
    const cleaned = value.replace(/[^0-9.]/g, '')
    const next = { ...profile, [key]: cleaned }
    const nextErrors = { ...errors }
    if (cleaned !== '' && Number(cleaned) < 0) nextErrors[key] = 'Must be positive'
    else delete nextErrors[key]
    setErrors(nextErrors)
    onChange(next)
  }

  return (
    <form className="card balance-input" onSubmit={(e) => e.preventDefault()}>
      <h2>Your CPF position</h2>
      <p className="muted">
        Stays in your browser. Only anonymised ranges are ever sent to Claude.
      </p>
      <div className="fields">
        {FIELDS.map((f) => (
          <label key={f.key} className="field">
            <span>{f.label}</span>
            <input
              type="text"
              inputMode={f.integer ? 'numeric' : 'decimal'}
              placeholder={f.placeholder}
              value={profile[f.key] ?? ''}
              onChange={(e) => handleField(f.key, e.target.value)}
            />
            {errors[f.key] && <small className="error">{errors[f.key]}</small>}
          </label>
        ))}
      </div>
      <label className="remember">
        <input
          type="checkbox"
          checked={remember}
          onChange={(e) => onRememberChange(e.target.checked)}
        />
        <span>Remember on this device (saves to localStorage)</span>
      </label>
    </form>
  )
}

import { useEffect, useRef, useState } from 'react'
import Icon from './icons.jsx'
import { sanitiseProfile } from '../utils/sanitiser.js'
import { askCPF } from '../utils/claudeClient.js'

// Chat with Claude over the SANITISED profile. The API key lives in sessionStorage
// (cleared when the tab closes). A "what was sent" panel reveals the exact
// anonymised payload — the proof that exact figures never leave the browser.

const STARTERS = [
  'Can I withdraw from my CPF at 55?',
  'Am I on track to hit the Full Retirement Sum?',
  'How does CPF interest grow my balances?',
]

export default function ChatInterface({ profile, apiKey, onApiKeyChange, seedQuestion, onSeedConsumed }) {
  const [messages, setMessages] = useState([])
  const [input, setInput] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)
  const [keyDraft, setKeyDraft] = useState('')
  const [showPayloadFor, setShowPayloadFor] = useState(null)
  const endRef = useRef(null)
  const lastSeed = useRef(null)

  async function send(question) {
    const q = (question ?? input).trim()
    if (!q || loading) return
    if (!apiKey) {
      setInput(q)
      setError('Add your Anthropic API key below to start asking.')
      return
    }
    setError(null)
    setInput('')
    const history = messages.map((m) => ({ role: m.role, content: m.content }))
    setMessages((m) => [...m, { role: 'user', content: q }])
    setLoading(true)
    try {
      const sanitised = sanitiseProfile(profile)
      const { text, sentPayload } = await askCPF({
        apiKey,
        sanitisedProfile: sanitised,
        rawProfile: profile,
        question: q,
        history,
      })
      setMessages((m) => [...m, { role: 'assistant', content: text, sentPayload }])
    } catch (e) {
      setError(e.message || 'Request failed.')
    } finally {
      setLoading(false)
    }
  }

  // A life-stage card handed us a question. Send it (or stage it if no key yet).
  useEffect(() => {
    if (!seedQuestion || seedQuestion === lastSeed.current) return
    lastSeed.current = seedQuestion
    if (apiKey) send(seedQuestion)
    else {
      setInput(seedQuestion)
      setError('Add your Anthropic API key below to ask this.')
    }
    onSeedConsumed?.()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [seedQuestion])

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth', block: 'nearest' })
  }, [messages, loading])

  return (
    <section className="card chat" id="assistant">
      <div className="section-head">
        <h2>Ask the assistant</h2>
        <p className="lede">
          Powered by Claude. It only ever sees your balances as ranges — never the exact figures.
        </p>
      </div>

      <div className="messages">
        {messages.length === 0 && (
          <div className="starter">
            <p className="muted">Try a question:</p>
            <div className="chips">
              {STARTERS.map((s) => (
                <button key={s} className="chip" onClick={() => send(s)} disabled={loading}>
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`}>
            <div className="bubble">{m.content}</div>
            {m.sentPayload && (
              <div className="transparency">
                <button
                  className="link"
                  onClick={() => setShowPayloadFor(showPayloadFor === i ? null : i)}
                >
                  <Icon name="lock" size={13} />
                  {showPayloadFor === i ? 'Hide what was sent' : 'See exactly what was sent'}
                </button>
                {showPayloadFor === i && (
                  <pre className="payload">{JSON.stringify(m.sentPayload, null, 2)}</pre>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && (
          <div className="msg assistant">
            <div className="bubble typing">Thinking…</div>
          </div>
        )}
        <div ref={endRef} />
      </div>

      {error && <p className="error">{error}</p>}

      <div className="composer">
        <input
          type="text"
          placeholder="Ask a CPF question…"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && send()}
          disabled={loading}
        />
        <button onClick={() => send()} disabled={loading || !input.trim()}>
          Send
        </button>
      </div>

      {!apiKey ? (
        <div className="key-entry">
          <label htmlFor="api-key">Your Anthropic API key</label>
          <div className="key-row">
            <input
              id="api-key"
              type="password"
              placeholder="sk-ant-…"
              value={keyDraft}
              onChange={(e) => setKeyDraft(e.target.value)}
            />
            <button onClick={() => onApiKeyChange(keyDraft.trim())} disabled={!keyDraft.trim()}>
              Save
            </button>
          </div>
          <p className="muted">Stored in this browser tab only and cleared when you close it.</p>
        </div>
      ) : (
        <button className="link clear-key" onClick={() => onApiKeyChange('')}>
          Clear API key
        </button>
      )}
    </section>
  )
}

