// Safe arithmetic evaluator for the assistant's calculator tool.
//
// A small recursive-descent parser — NO eval/Function, so a model-supplied
// expression can never execute arbitrary code. Supports + - * / % ^, unary +/-,
// parentheses and decimal numbers.
//
//   expr   := term (('+' | '-') term)*
//   term   := factor (('*' | '/' | '%') factor)*
//   factor := unary ('^' factor)?        // ^ is right-associative
//   unary  := ('+' | '-') unary | primary
//   primary:= number | '(' expr ')'

function tokenize(input) {
  const tokens = []
  const src = String(input)
  let i = 0
  while (i < src.length) {
    const c = src[i]
    if (c === ' ' || c === '\t' || c === '\n' || c === ',' || c === '_') {
      i++
      continue
    }
    if ('+-*/%^()'.includes(c)) {
      tokens.push({ type: c })
      i++
      continue
    }
    if ((c >= '0' && c <= '9') || c === '.') {
      let num = ''
      while (i < src.length && ((src[i] >= '0' && src[i] <= '9') || src[i] === '.')) {
        num += src[i++]
      }
      if (!/^\d*\.?\d+$|^\d+\.$/.test(num)) throw new Error(`Invalid number "${num}"`)
      tokens.push({ type: 'num', value: parseFloat(num) })
      continue
    }
    throw new Error(`Unexpected character "${c}"`)
  }
  return tokens
}

export function evaluate(expression) {
  if (expression == null || String(expression).trim() === '') {
    throw new Error('Empty expression')
  }
  const tokens = tokenize(expression)
  let pos = 0
  const peek = () => tokens[pos]
  const next = () => tokens[pos++]

  function parseExpr() {
    let left = parseTerm()
    while (peek() && (peek().type === '+' || peek().type === '-')) {
      const op = next().type
      const right = parseTerm()
      left = op === '+' ? left + right : left - right
    }
    return left
  }

  function parseTerm() {
    let left = parseFactor()
    while (peek() && (peek().type === '*' || peek().type === '/' || peek().type === '%')) {
      const op = next().type
      const right = parseFactor()
      if ((op === '/' || op === '%') && right === 0) throw new Error('Division by zero')
      left = op === '*' ? left * right : op === '/' ? left / right : left % right
    }
    return left
  }

  function parseFactor() {
    const base = parseUnary()
    if (peek() && peek().type === '^') {
      next()
      const exp = parseFactor() // right-associative
      return Math.pow(base, exp)
    }
    return base
  }

  function parseUnary() {
    if (peek() && (peek().type === '+' || peek().type === '-')) {
      const op = next().type
      const val = parseUnary()
      return op === '-' ? -val : val
    }
    return parsePrimary()
  }

  function parsePrimary() {
    const t = peek()
    if (!t) throw new Error('Unexpected end of expression')
    if (t.type === 'num') {
      next()
      return t.value
    }
    if (t.type === '(') {
      next()
      const val = parseExpr()
      if (!peek() || peek().type !== ')') throw new Error('Missing closing parenthesis')
      next()
      return val
    }
    throw new Error(`Unexpected token "${t.type}"`)
  }

  const result = parseExpr()
  if (pos < tokens.length) throw new Error(`Unexpected token "${peek().type}"`)
  if (!Number.isFinite(result)) throw new Error('Result is not a finite number')
  return result
}

