export const MAX_TOKENS = 1024
const MAX_TOOL_ROUNDS = 5 // safety cap on the agentic loop

// Calculator tool — executed locally in the browser, so no computation leaves
// the device. The model decides when a query needs arithmetic and calls it.
const CALCULATOR_TOOL = {
  name: 'calculator',
  description:
    'Evaluate an arithmetic expression and return the numeric result. Use this for ANY calculation a question needs — gaps to a target, percentages, monthly figures, multi-year sums, payout comparisons. Supports + - * / % ^ and parentheses. Pass one expression string, e.g. "220400 - 150000" or "6000 * 0.23 * 12". Do not do non-trivial arithmetic in your head; call this tool instead.',
  input_schema: {
    type: 'object',
    properties: {
      expression: { type: 'string', description: 'The arithmetic expression to evaluate.' },
    },
    required: ['expression'],
  },
}

const SYSTEM_PROMPT = `You are a CPF (Singapore Central Provident Fund) planning assistant.

You receive the user's financial position ONLY as anonymised RANGES (bands), never exact dollar amounts, plus a structured CPF rules knowledge base. This is a deliberate privacy design.

Rules for your answers:
- Reason and answer in terms of the bands you are given. NEVER ask the user for their exact balances or income — you cannot receive them and should not request them.
- Ground your answers in the provided CPF knowledge base. If something isn't covered, say so rather than inventing figures.
- When a question needs arithmetic (e.g. how far a band midpoint is from a retirement sum, contribution amounts, multi-year growth), use the calculator tool rather than computing in your head. When reasoning about the user's balances, compute with the midpoint or edges of the band you were given, and say you are doing so.
- Be concise, concrete and practical. Use Singapore dollar context.
- Always end with a one-line disclaimer: "This is general information, not financial advice — verify against cpf.gov.sg."`

export function createClient(apiKey) {
  return new Anthropic({ apiKey, dangerouslyAllowBrowser: true })
}

// Build the user-facing content block from sanitised data only.
function buildUserContent({ sanitisedProfile, rulesContext, question }) {
  const profileLines = [
    'My CPF position (anonymised ranges):',
    `- Ordinary Account: ${sanitisedProfile.oaBand}`,
    `- Special Account: ${sanitisedProfile.saBand}`,
    `- MediSave Account: ${sanitisedProfile.maBand}`,
    `- Total CPF: ${sanitisedProfile.totalBand}`,
    sanitisedProfile.incomeBand ? `- Monthly income: ${sanitisedProfile.incomeBand}` : null,
    sanitisedProfile.age != null ? `- Age: ${sanitisedProfile.age}` : null,
  ].filter(Boolean)

  return `${profileLines.join('\n')}\n\n${rulesContext}\n\nQuestion: ${question}`
}

// Ask a CPF question. `rawProfile` is passed ONLY to the leak guard so we can
// assert no exact figure slipped into the outgoing request.
export async function askCPF({ apiKey, sanitisedProfile, rawProfile, question, history = [] }) {
  if (!apiKey) throw new Error('Missing Anthropic API key.')

  const selection = selectRelevantSections(question)
  const rulesContext = buildRulesContext(selection)
  const userContent = buildUserContent({ sanitisedProfile, rulesContext, question })

  const messages = [
    ...history.map((m) => ({ role: m.role, content: m.content })),
    { role: 'user', content: userContent },
  ]

  // Final privacy gate: serialise everything we're about to send and verify no
  // raw amount appears. Throws (and we never call the API) if it does.
  assertNoRawAmounts(JSON.stringify({ system: SYSTEM_PROMPT, messages }), rawProfile)

  const client = createClient(apiKey)
  const resp = await client.messages.create({
    model: MODEL,
    max_tokens: MAX_TOKENS,
    system: SYSTEM_PROMPT,
    messages,
  })

  const text = resp.content
    .filter((block) => block.type === 'text')
    .map((block) => block.text)
    .join('\n')

  // Return the answer plus exactly what was sent, for the transparency panel.
  return { text, sentPayload: { system: SYSTEM_PROMPT, messages, model: MODEL } }
}

