import { describe, it, expect } from 'vitest'
import { evaluate } from './calculator.js'

describe('evaluate', () => {
  it('does basic arithmetic with precedence', () => {
    expect(evaluate('1 + 2 * 3')).toBe(7)
    expect(evaluate('(1 + 2) * 3')).toBe(9)
    expect(evaluate('220400 - 150000')).toBe(70400)
    expect(evaluate('10 / 4')).toBe(2.5)
  })

  it('handles a CPF-style computation', () => {
    expect(evaluate('6000 * 0.23 * 12')).toBeCloseTo(16560)
    expect(evaluate('220400 - 125000')).toBe(95400)
  })

  it('supports unary minus, exponent and modulo', () => {
    expect(evaluate('-5 + 3')).toBe(-2)
    expect(evaluate('2 ^ 3 ^ 2')).toBe(512) // right-associative
    expect(evaluate('10 % 3')).toBe(1)
  })

  it('ignores commas and underscores in numbers', () => {
    expect(evaluate('1,000 + 2,500')).toBe(3500)
  })

  it('throws on division by zero', () => {
    expect(() => evaluate('5 / 0')).toThrow(/Division by zero/)
  })

  it('throws on malformed input', () => {
    expect(() => evaluate('2 +')).toThrow()
    expect(() => evaluate('2 ** 3')).toThrow()
    expect(() => evaluate('(1 + 2')).toThrow(/parenthesis/)
    expect(() => evaluate('')).toThrow(/Empty/)
  })

  it('never executes code (no eval escape)', () => {
    expect(() => evaluate('process')).toThrow()
    expect(() => evaluate('1; alert(1)')).toThrow()
  })
})

