        rawProfile: profile,
        question: q,
        history,
      })
      setMessages((m) => [...m, { role: 'assistant', content: text, toolCalls, sentPayload }])
    } catch (e) {
      setError(e.message || 'Request failed.')
    } finally {
      setLoading(false)
    }
  }

