export async function askCPF({ apiKey, sanitisedProfile, rawProfile, question, history = [] }) {
  if (!apiKey) throw new Error('Missing Anthropic API key.')

  const selection = selectRelevantSections(question)
  const rulesContext = buildRulesContext(selection)
  const { content: userContent, profileBlock } = buildUserContent({
    sanitisedProfile,
    rulesContext,
    question,
  })

  // Privacy gate: the profile block is the ONLY text we generate from the user's
  // raw numbers. Verify our sanitisation emitted no exact amount. We deliberately
  // do not scan the public knowledge base — its dollar figures may legitimately
  // match a user's balance and would otherwise cause false-positive aborts.
  assertNoRawAmounts(profileBlock, rawProfile)

  const messages = [
    ...history.map((m) => ({ role: m.role, content: m.content })),
    { role: 'user', content: userContent },
  ]

  const client = createClient(apiKey)
  const toolCalls = [] // surfaced to the UI so the user sees what was computed

  // Agentic loop: the model may call the calculator (locally executed) before
  // producing its final answer.
  for (let round = 0; round <= MAX_TOOL_ROUNDS; round++) {
    const resp = await client.messages.create({
      model: MODEL,
      max_tokens: MAX_TOKENS,
      system: SYSTEM_PROMPT,
      messages,
      tools: [CALCULATOR_TOOL],
    })

    messages.push({ role: 'assistant', content: resp.content })

    if (resp.stop_reason === 'tool_use') {
      const toolResults = []
      for (const block of resp.content) {
        if (block.type !== 'tool_use' || block.name !== 'calculator') continue
        const expression = block.input?.expression ?? ''
        let result
        let isError = false
        try {
          result = String(evaluate(expression))
        } catch (e) {
          result = `Error: ${e.message}`
          isError = true
        }
        toolCalls.push({ expression, result })
        toolResults.push({
          type: 'tool_result',
          tool_use_id: block.id,
          content: result,
          is_error: isError,
        })
      }
      messages.push({ role: 'user', content: toolResults })
      continue // let the model use the results
    }

    // Final answer.
    const text = resp.content
      .filter((b) => b.type === 'text')
      .map((b) => b.text)
      .join('\n')
    return {
      text,
      toolCalls,
      sentPayload: { system: SYSTEM_PROMPT, messages, model: MODEL, tools: ['calculator'] },
    }
  }

  throw new Error('Calculation loop did not converge — please rephrase your question.')
}

