  const client = createClient(apiKey)
  const toolCalls = [] // surfaced to the UI so the user sees what was computed

  // Agentic loop: the model may call the calculator (locally executed) before
  // producing its final answer.
  for (let round = 0; round <= MAX_TOOL_ROUNDS; round++) {
    const resp = await client.messages.create({
      model: MODEL,
      max_tokens: MAX_TOKENS,
      system: SYSTEM_PROMPT,
      messages,
      tools: [CALCULATOR_TOOL],
    })

    messages.push({ role: 'assistant', content: resp.content })

    if (resp.stop_reason === 'tool_use') {
      const toolResults = []
      for (const block of resp.content) {
        if (block.type !== 'tool_use' || block.name !== 'calculator') continue
        const expression = block.input?.expression ?? ''
        let result
        let isError = false
        try {
          result = String(evaluate(expression))
        } catch (e) {
          result = `Error: ${e.message}`
          isError = true
        }
        toolCalls.push({ expression, result })
        toolResults.push({
